/* --- bayes_opt_genom_state reader ------------------------------------- */

genom_state_component *
genom_bayes_opt_client_genom_state_data(
    genom_client h
)
{
  return &(h->ports->genom_state.data);
}

genom_event
genom_bayes_opt_client_genom_state_read(
  genom_client h,
  genom_state_component *data)
{
  POSTER_ID *id;
  int searched = 0;
  char *addr;
  int s;

  /* cached id */
  id = &h->ports->genom_state.id;
  if (!data)
    data = &(h->ports->genom_state.data);

  do {
    if (!*id) {
      char name[H2_DEV_MAX_NAME];
      int n;
      n = snprintf(name, sizeof(name), "%s/genom_state", h->instance);
      if (n <= 0 || n >= (signed)sizeof(name)) {
        return genom_syserr(
          &(genom_syserr_detail){.code = ENAMETOOLONG}, &h->context);
      }

      if (posterFind(name, id) != OK) {
        genom_mwerr_detail d;
        char msg[sizeof(d.what)];
        h2getErrMsg(errnoGet(), msg, sizeof(msg));
        if (snprintf(d.what, sizeof(d.what), "%s port: %s", name, msg) < 0)
          strncpy(d.what, "internal error", sizeof(d.what));
        return genom_mwerr(&d, &h->context);
      }
      searched = 1;
    }

    if (posterTake(*id, POSTER_READ) != OK) {
      genom_mwerr_detail d;
      char msg[sizeof(d.what)];
      int code = errnoGet();
      if (!searched && code == S_posterLib_POSTER_CLOSED) {
        *id = NULL; continue /* try to refetch poster id */;
      }

      h2getErrMsg(code, msg, sizeof(msg));
      if (snprintf(d.what, sizeof(d.what),
                   "%s/genom_state port: %s", h->instance, msg) < 0)
        strncpy(d.what, "internal error", sizeof(d.what));
      return genom_mwerr(&d, &h->context);
    }

    break;
  } while(1);

  addr = posterAddr(*id);
  s = genom_bayes_opt_genom_state_decode(addr, data);
  posterGive(*id);

  if (s)
    return genom_syserr(&(genom_syserr_detail){.code = s}, &h->context);
  return genom_ok;
}

genom_event
genom_bayes_opt_client_genom_state_port(
  genom_client h,
  genom_state_component *data)
  __attribute((alias("genom_bayes_opt_client_genom_state_read")));


